"use client";
import { useState } from "react";
import { useRouter } from "next/navigation";
import { MOCK_MATCHES, MOCK_ADVISORS, type MockAdvisor, type MockMatch } from "@/lib/mock-data";

interface HydratedMatch { match: MockMatch; advisor: MockAdvisor }

export default function MatchedCXOPage() {
  const router = useRouter();
  const [active, setActive] = useState<HydratedMatch | null>(null);

  const visible: HydratedMatch[] = MOCK_MATCHES
    .filter(m => m.status !== "archived")
    .map(m => ({ match: m, advisor: MOCK_ADVISORS[m.advisorUid] }))
    .filter(r => !!r.advisor);

  function startConversation(row: HydratedMatch) {
    router.push(`/dashboard/messages?thread=t_mock_${row.match.advisorUid}`);
  }

  return (
    <div>
      <div className="mb-5">
        <h1 className="text-[24px] font-semibold tracking-tight">Matched CXO</h1>
        <p className="text-sm text-gray-500 mt-1">Executives our team has hand-picked for your needs. Reach out to start a conversation.</p>
      </div>
      <div className="text-[12.5px] text-gray-500 mb-3">{visible.length} match{visible.length === 1 ? "" : "es"}</div>
      <div className="flex flex-col gap-3">
        {visible.map(row => (
          <MatchRow key={row.match.id} row={row} onView={() => setActive(row)} onSend={() => startConversation(row)} />
        ))}
      </div>
      {active && (
        <MatchProfileModal row={active} onClose={() => setActive(null)} onSend={() => { startConversation(active); setActive(null); }} />
      )}
    </div>
  );
}

function MatchRow({ row, onView, onSend }: { row: HydratedMatch; onView: () => void; onSend: () => void }) {
  const a = row.advisor;
  const name = [a.firstName, a.lastName].filter(Boolean).join(" ");
  const initials = ((a.firstName?.[0] || "") + (a.lastName?.[0] || "")).toUpperCase();
  const tags = (a.selectedRoles || []).slice(0, 3);
  return (
    <div className="bg-white border border-gray-200 rounded-xl p-5 hover:border-blue-500 hover:shadow-sm transition-all">
      <div className="flex items-start gap-4">
        <button type="button" onClick={onView} className="shrink-0" aria-label={`View ${name}'s profile`}>
          <div className="w-14 h-14 rounded-full bg-blue-600 text-white grid place-items-center font-bold text-lg">{initials}</div>
        </button>
        <button type="button" onClick={onView} className="min-w-0 flex-1 text-left">
          <div className="text-[15px] font-semibold text-gray-900 truncate">{name}</div>
          {a.headline && <div className="text-[13px] text-gray-600 line-clamp-2 mt-0.5">{a.headline}</div>}
          <div className="flex flex-wrap items-center gap-1.5 mt-2">
            {tags.map(t => <span key={t} className="text-[11px] font-medium px-2 py-0.5 rounded-full bg-blue-50 text-blue-700 border border-blue-200">{t}</span>)}
            {a.city && <span className="text-[12px] text-gray-500 ml-1">{a.city}</span>}
            {a.hourlyRate && <span className="text-[12px] font-semibold text-gray-700 ml-1">${a.hourlyRate}/hr</span>}
          </div>
          {row.match.note && (
            <div className="mt-2 text-[12.5px] text-gray-600 italic line-clamp-2">&ldquo;{row.match.note}&rdquo;</div>
          )}
        </button>
        <div className="shrink-0">
          <button type="button" onClick={onSend} className="px-4 py-2 rounded-lg text-[13px] font-semibold text-white bg-blue-600 hover:bg-blue-700 whitespace-nowrap">
            Send Message
          </button>
        </div>
      </div>
    </div>
  );
}

function MatchProfileModal({ row, onClose, onSend }: { row: HydratedMatch; onClose: () => void; onSend: () => void }) {
  const a = row.advisor;
  const name = [a.firstName, a.lastName].filter(Boolean).join(" ");
  const initials = ((a.firstName?.[0] || "") + (a.lastName?.[0] || "")).toUpperCase();
  return (
    <div onClick={e => { if (e.target === e.currentTarget) onClose(); }}
      style={{ position: "fixed", inset: 0, zIndex: 9000, background: "rgba(15,23,42,0.40)", display: "flex", alignItems: "flex-start", justifyContent: "center", padding: "5vh 16px", overflowY: "auto" }}>
      <div style={{ background: "#fff", borderRadius: 14, boxShadow: "0 20px 60px rgba(0,0,0,0.25)", display: "flex", flexDirection: "column", width: "100%", maxWidth: 720, maxHeight: "90vh", colorScheme: "light" }}>
        <div className="flex items-center justify-between px-5 py-4 border-b border-gray-200">
          <h3 className="text-[16px] font-bold m-0">Matched CXO</h3>
          <button type="button" onClick={onClose} className="p-1 rounded-md text-gray-500 hover:bg-gray-100">
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
          </button>
        </div>
        <div className="flex-1 overflow-y-auto px-5 py-5">
          <div className="flex items-start gap-4 mb-4">
            <div className="w-16 h-16 rounded-full bg-blue-600 text-white grid place-items-center font-bold text-xl shrink-0">{initials}</div>
            <div className="min-w-0">
              <div className="text-[18px] font-bold text-gray-900">{name}</div>
              {a.headline && <p className="text-[13.5px] text-gray-600 m-0">{a.headline}</p>}
              <div className="text-[12.5px] text-gray-500 mt-1">{a.city}</div>
            </div>
          </div>
          {row.match.note && <Section title="Why this match"><p className="text-[13.5px] leading-[1.6] text-gray-900">{row.match.note}</p></Section>}
          {a.about && <Section title="About"><p className="text-[13.5px] leading-[1.6] text-gray-900 whitespace-pre-wrap">{a.about}</p></Section>}
          {a.selectedIndustries?.length > 0 && <Section title="Industries"><Chips items={a.selectedIndustries} /></Section>}
          {a.engagementTypes?.length > 0 && <Section title="Engagement types"><Chips items={a.engagementTypes} /></Section>}
          {a.skills?.length > 0 && <Section title="Core skills"><Chips items={a.skills} gray /></Section>}
        </div>
        <div className="flex justify-end gap-2.5 px-5 py-3.5 border-t border-gray-200">
          <button type="button" onClick={onClose} className="px-4 py-2 rounded-lg text-[13.5px] font-semibold border border-gray-300 bg-white hover:bg-gray-50">Close</button>
          <button type="button" onClick={onSend} className="px-5 py-2 rounded-lg text-[13.5px] font-semibold text-white bg-blue-600 hover:bg-blue-700">Send Message</button>
        </div>
      </div>
    </div>
  );
}

function Section({ title, children }: { title: string; children: React.ReactNode }) {
  return <div className="mb-4 last:mb-0"><h4 className="text-[11.5px] font-bold uppercase tracking-wider text-gray-600 mb-2">{title}</h4>{children}</div>;
}
function Chips({ items, gray }: { items: string[]; gray?: boolean }) {
  return (
    <div className="flex flex-wrap gap-1.5">
      {items.map(i => <span key={i} className={["inline-block px-2.5 py-0.5 rounded-full text-[12px] font-medium border", gray ? "bg-gray-100 border-gray-200 text-gray-700" : "bg-blue-50 border-blue-200 text-blue-700"].join(" ")}>{i}</span>)}
    </div>
  );
}
